  constructor(nums){
    this.n=nums.length;
    this.tree=Array(this.n+1).fill(0);
    this.nums=[...nums];
    for(let i=0;i<nums.length;i++)this._upd(i+1,nums[i]);
  }
  _upd(i,d){for(;i<=this.n;i+=i&-i)this.tree[i]+=d;}
  _sum(i){let s=0;for(;i>0;i-=i&-i)s+=this.tree[i];return s;}
  update(i,v){this._upd(i+1,v-this.nums[i]);this.nums[i]=v;}
  sumRange(l,r){return this._sum(r+1)-this._sum(l);}
